import{_ as t,c as r,o as a,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Premier lancement : Maîtriser le répertoire de données | Antigravity Tools","description":"Apprenez l'emplacement du répertoire de données et la gestion des journaux d'Antigravity Tools. Maîtrisez l'ouverture du répertoire de données depuis les paramètres, le nettoyage des journaux, l'exécution en barre d'état et le démarrage automatique, en distinguant les deux types de démarrage automatique.","frontmatter":{"title":"Premier lancement : Maîtriser le répertoire de données | Antigravity Tools","sidebarTitle":"Trouver le répertoire de données","subtitle":"Essentiel au premier lancement : répertoire de données, journaux, barre d'état système et démarrage automatique","description":"Apprenez l'emplacement du répertoire de données et la gestion des journaux d'Antigravity Tools. Maîtrisez l'ouverture du répertoire de données depuis les paramètres, le nettoyage des journaux, l'exécution en barre d'état et le démarrage automatique, en distinguant les deux types de démarrage automatique.","tags":["Premier lancement","Répertoire de données","Journaux","Barre d'état","Démarrage automatique"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}`),o={name:"fr/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function i(n,e,d,u,l,c){return a(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="essentiel-au-premier-lancement-repertoire-de-donnees-journaux-barre-d-etat-et-demarrage-automatique" tabindex="-1">Essentiel au premier lancement : Répertoire de données, journaux, barre d&#39;état et démarrage automatique <a class="header-anchor" href="#essentiel-au-premier-lancement-repertoire-de-donnees-journaux-barre-d-etat-et-demarrage-automatique" aria-label="Permalink to &quot;Essentiel au premier lancement : Répertoire de données, journaux, barre d&#39;état et démarrage automatique&quot;">​</a></h1><p>De nombreuses capacités d&#39;Antigravity Tools qui semblent &quot;magiques&quot; (pool de comptes, quotas, surveillance, statistiques, exécution en arrière-plan) reposent en fin de compte sur deux éléments : le <strong>répertoire de données</strong> et les <strong>journaux</strong>. Si vous comprenez bien ces deux éléments dès le premier lancement, vous gagnerez beaucoup de temps lors du dépannage.</p><h2 id="qu-est-ce-que-le-repertoire-de-donnees" tabindex="-1">Qu&#39;est-ce que le répertoire de données ? <a class="header-anchor" href="#qu-est-ce-que-le-repertoire-de-donnees" aria-label="Permalink to &quot;Qu&#39;est-ce que le répertoire de données ?&quot;">​</a></h2><p>Le <strong>répertoire de données</strong> est le dossier où Antigravity Tools enregistre son état local : les fichiers JSON de comptes, les fichiers liés aux quotas, les fichiers journaux, ainsi que les bases de données SQLite de Token Stats et Proxy Monitor sont tous stockés ici. Lorsque vous effectuez des sauvegardes, des migrations ou des dépannages, une fois que vous avez localisé ce répertoire, vous pouvez trouver la source de données fiable.</p><h2 id="ce-que-vous-saurez-faire-apres-ce-cours" tabindex="-1">Ce que vous saurez faire après ce cours <a class="header-anchor" href="#ce-que-vous-saurez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous saurez faire après ce cours&quot;">​</a></h2><ul><li>Savoir où se trouve le répertoire de données d&#39;Antigravity Tools (et pouvoir l&#39;ouvrir en un clic)</li><li>Comprendre quels fichiers doivent être sauvegardés et lesquels sont des journaux/cache</li><li>Pouvoir localiser rapidement les journaux et la base de données de surveillance en cas de dépannage</li><li>Comprendre la différence entre &quot;fermer la fenêtre&quot; et &quot;quitter l&#39;application&quot; (barre d&#39;état système permanente)</li><li>Distinguer les deux types de démarrage automatique : démarrage au démarrage du système vs démarrage automatique du proxy inverse</li></ul><h2 id="vos-difficultes-actuelles" tabindex="-1">Vos difficultés actuelles <a class="header-anchor" href="#vos-difficultes-actuelles" aria-label="Permalink to &quot;Vos difficultés actuelles&quot;">​</a></h2><ul><li>Vous voulez sauvegarder/migrer vos comptes, mais vous ne savez pas où ils sont enregistrés</li><li>L&#39;interface signale une erreur / l&#39;appel au proxy inverse échoue, mais vous ne trouvez pas les journaux</li><li>Vous avez fermé la fenêtre en pensant que l&#39;application s&#39;était arrêtée, mais elle continue de fonctionner en arrière-plan</li></ul><h2 id="quand-utiliser-cette-approche" tabindex="-1">Quand utiliser cette approche <a class="header-anchor" href="#quand-utiliser-cette-approche" aria-label="Permalink to &quot;Quand utiliser cette approche&quot;">​</a></h2><ul><li>Vous venez d&#39;installer Antigravity Tools et voulez confirmer &quot;où les données sont stockées&quot;</li><li>Vous préparez un changement d&#39;ordinateur / une réinstallation du système et voulez sauvegarder d&#39;abord vos comptes et vos données statistiques</li><li>Vous devez dépanner : échec OAuth, échec de rafraîchissement des quotas, échec de démarrage du proxy inverse, erreur 401/429 lors des appels</li></ul><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><ul><li>Antigravity Tools installé et fonctionnel</li><li>Vous pouvez accéder à la page Settings (entrée dans le coin supérieur droit / barre latérale)</li><li>Votre compte système a les permissions nécessaires pour accéder à votre répertoire Home</li></ul><div class="warning custom-block"><p class="custom-block-title">Rappel</p><p>Ce cours vous indiquera quels fichiers sont de &quot;vraies données&quot;, mais nous ne recommandons pas de modifier manuellement ces fichiers. Pour modifier la configuration, privilégiez l&#39;interface utilisateur.</p></div><h2 id="approche-fondamentale" tabindex="-1">Approche fondamentale <a class="header-anchor" href="#approche-fondamentale" aria-label="Permalink to &quot;Approche fondamentale&quot;">​</a></h2><p>Retenez d&#39;abord une phrase :</p><p>&quot;<strong>Le répertoire de données est la source unique de vérité de l&#39;état local ; les journaux sont le premier point d&#39;entrée pour le dépannage.</strong>&quot;</p><p>Antigravity Tools crée un répertoire de données <code>.antigravity_tools</code> dans votre répertoire Home et y place les comptes, journaux, bases de données statistiques, etc. (le répertoire sera créé automatiquement s&#39;il n&#39;existe pas).</p><p>Simultanément, il active par défaut la barre d&#39;état : lorsque vous fermez la fenêtre, l&#39;application ne se ferme pas immédiatement, mais se cache dans la barre d&#39;état et continue de fonctionner en arrière-plan.</p><h2 id="suivez-les-etapes" tabindex="-1">Suivez les étapes <a class="header-anchor" href="#suivez-les-etapes" aria-label="Permalink to &quot;Suivez les étapes&quot;">​</a></h2><h3 id="etape-1-ouvrir-le-repertoire-de-donnees-depuis-la-page-des-parametres" tabindex="-1">Étape 1 : Ouvrir le répertoire de données depuis la page des paramètres <a class="header-anchor" href="#etape-1-ouvrir-le-repertoire-de-donnees-depuis-la-page-des-parametres" aria-label="Permalink to &quot;Étape 1 : Ouvrir le répertoire de données depuis la page des paramètres&quot;">​</a></h3><p><strong>Pourquoi</strong> Commencez par localiser avec précision le répertoire de données. Par la suite, que ce soit pour la sauvegarde ou le dépannage, vous aurez un &quot;point de repère&quot;.</p><p>Dans Antigravity Tools, ouvrez Settings, puis basculez sur Advanced.</p><p>Vous verrez un champ en lecture seule pour &quot;Répertoire de données&quot; (il affichera le chemin réel), avec un bouton Ouvrir à côté.</p><p>Cliquez sur le bouton Ouvrir.</p><p><strong>Ce que vous devriez voir</strong> : L&#39;explorateur de fichiers système ouvre un répertoire, avec un chemin similaire à <code>~/.antigravity_tools/</code>.</p><h3 id="etape-2-confirmer-le-chemin-de-votre-repertoire-de-donnees-multiplateforme" tabindex="-1">Étape 2 : Confirmer le chemin de votre répertoire de données (multiplateforme) <a class="header-anchor" href="#etape-2-confirmer-le-chemin-de-votre-repertoire-de-donnees-multiplateforme" aria-label="Permalink to &quot;Étape 2 : Confirmer le chemin de votre répertoire de données (multiplateforme)&quot;">​</a></h3><p><strong>Pourquoi</strong> Pour écrire des scripts de sauvegarde ou dépanner depuis la ligne de commande par la suite, vous devez connaître le chemin réel de ce répertoire sur votre système.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-ym8ur" id="tab-tqt3ksy" checked><label data-title="macOS/Linux" for="tab-tqt3ksy">macOS/Linux</label><input type="radio" name="group-ym8ur" id="tab-jlYU8HL"><label data-title="Windows" for="tab-jlYU8HL">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>Ce que vous devriez voir</strong> : Le répertoire existe (si c&#39;est la première fois que vous ouvrez la page des paramètres, le répertoire sera créé automatiquement).</p><h3 id="etape-3-connaitre-les-fichiers-cles-dans-le-repertoire-de-donnees" tabindex="-1">Étape 3 : Connaître les &quot;fichiers clés&quot; dans le répertoire de données <a class="header-anchor" href="#etape-3-connaitre-les-fichiers-cles-dans-le-repertoire-de-donnees" aria-label="Permalink to &quot;Étape 3 : Connaître les &quot;fichiers clés&quot; dans le répertoire de données&quot;">​</a></h3><p><strong>Pourquoi</strong> Tous les fichiers ne méritent pas d&#39;être sauvegardés. Commençons par distinguer &quot;quels sont les données de comptes&quot; et &quot;quels sont les bases de données statistiques/journaux&quot;.</p><p>Les noms de fichiers ci-dessous proviennent du code source du projet et sont tous fixes :</p><table tabindex="0"><thead><tr><th>Contenu que vous verrez</th><th>Utilité</th><th>Ce qui vous intéresse</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>Index des comptes (contient la liste des comptes/compte actuel)</td><td>Recommandé de sauvegarder ensemble lors de la migration de comptes</td></tr><tr><td><code>accounts/</code></td><td>Un fichier <code>*.json</code> par compte</td><td>C&#39;est le corps principal des données de compte</td></tr><tr><td><code>logs/</code></td><td>Répertoire des journaux de l&#39;application</td><td>Priorité pour le dépannage</td></tr><tr><td><code>token_stats.db</code></td><td>Base de données SQLite de Token Stats</td><td>Les données que vous voyez sur la page Token Stats proviennent de cette base</td></tr><tr><td><code>proxy_logs.db</code></td><td>Base de données SQLite de Proxy Monitor</td><td>Les journaux de requêtes que vous voyez sur la page Monitor proviennent de cette base</td></tr><tr><td><code>warmup_history.json</code></td><td>Historique local de Smart Warmup</td><td>Principalement utilisé pour éviter les warmup en double</td></tr><tr><td><code>update_settings.json</code></td><td>Paramètres de vérification de mises à jour (vérification automatique/intervalle, etc.)</td><td>Généralement pas besoin de le modifier manuellement</td></tr></tbody></table><p><strong>Ce que vous devriez voir</strong> : Au moins le répertoire <code>logs/</code> ; si vous n&#39;avez pas encore ajouté de comptes, <code>accounts.json</code>/<code>accounts/</code> peuvent ne pas encore apparaître.</p><h3 id="etape-4-memoriser-l-emplacement-des-journaux-essentiel-pour-le-depannage" tabindex="-1">Étape 4 : Mémoriser l&#39;emplacement des journaux (essentiel pour le dépannage) <a class="header-anchor" href="#etape-4-memoriser-l-emplacement-des-journaux-essentiel-pour-le-depannage" aria-label="Permalink to &quot;Étape 4 : Mémoriser l&#39;emplacement des journaux (essentiel pour le dépannage)&quot;">​</a></h3><p><strong>Pourquoi</strong> Les messages d&#39;erreur de l&#39;interface ne donnent généralement que le &quot;symptôme&quot;, la cause réelle de l&#39;échec (par exemple échec de requête, échec de lecture/écriture de fichier) se trouve souvent dans les journaux.</p><p>Antigravity Tools écrit les journaux dans le répertoire <code>logs/</code> du répertoire de données.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-nMOev" id="tab-wfOBDBF" checked><label data-title="macOS/Linux" for="tab-wfOBDBF">macOS/Linux</label><input type="radio" name="group-nMOev" id="tab-n5n_NJA"><label data-title="Windows" for="tab-n5n_NJA">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>Ce que vous devriez voir</strong> : Le répertoire contient des fichiers journaux avec rotation quotidienne (les noms de fichiers commencent par <code>app.log</code>).</p><h3 id="etape-5-pour-vider-les-journaux-utilisez-le-nettoyage-en-un-clic-de-la-page-des-parametres" tabindex="-1">Étape 5 : Pour &quot;vider les journaux&quot;, utilisez le nettoyage en un clic de la page des paramètres <a class="header-anchor" href="#etape-5-pour-vider-les-journaux-utilisez-le-nettoyage-en-un-clic-de-la-page-des-parametres" aria-label="Permalink to &quot;Étape 5 : Pour &quot;vider les journaux&quot;, utilisez le nettoyage en un clic de la page des paramètres&quot;">​</a></h3><p><strong>Pourquoi</strong> Pour certains problèmes, vous voulez seulement reproduire une fois, puis conserver uniquement les journaux de cette fois ; dans ce cas, vider d&#39;abord les journaux facilitera la comparaison.</p><p>Dans Settings -&gt; Advanced, trouvez la zone des journaux, cliquez sur &quot;Vider les journaux&quot;.</p><p><strong>Ce que vous devriez voir</strong> : Une boîte de confirmation apparaît ; après confirmation, un message de nettoyage réussi s&#39;affiche.</p><div class="tip custom-block"><p class="custom-block-title">Deux choses dont vous vous inquiéterez peut-être</p><ul><li>Les journaux effectuent automatiquement une &quot;rotation quotidienne&quot; et tentent de nettoyer les anciens journaux de plus de 7 jours au démarrage.</li><li>&quot;Vider les journaux&quot; tronque les fichiers journaux à 0 octets, ce qui permet aux processus en cours d&#39;écrire dans le même descripteur de fichier.</li></ul></div><h3 id="etape-6-comprendre-la-difference-entre-fermer-la-fenetre-et-quitter-l-application-barre-d-etat" tabindex="-1">Étape 6 : Comprendre la différence entre &quot;fermer la fenêtre&quot; et &quot;quitter l&#39;application&quot; (barre d&#39;état) <a class="header-anchor" href="#etape-6-comprendre-la-difference-entre-fermer-la-fenetre-et-quitter-l-application-barre-d-etat" aria-label="Permalink to &quot;Étape 6 : Comprendre la différence entre &quot;fermer la fenêtre&quot; et &quot;quitter l&#39;application&quot; (barre d&#39;état)&quot;">​</a></h3><p><strong>Pourquoi</strong> Antigravity Tools active par défaut la barre d&#39;état ; lorsque vous cliquez sur la fermeture en haut à droite de la fenêtre, l&#39;application se cache dans la barre d&#39;état et continue de fonctionner. Si vous pensez qu&#39;elle s&#39;est arrêtée, il est facile d&#39;avoir l&#39;illusion &quot;le port est toujours occupé/l&#39;application tourne encore en arrière-plan&quot;.</p><p>Vous pouvez utiliser ce petit processus pour confirmer :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Action : Fermer la fenêtre (pas quitter)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Étape 1                 Étape 2                             │</span></span>
<span class="line"><span>│  Cliquer sur fermer  →  Aller chercher l&#39;icône dans la     │</span></span>
<span class="line"><span>│  la fenêtre               barre d&#39;état système/la barre     │</span></span>
<span class="line"><span>│                           de menu                            │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ce que vous devriez voir : L&#39;icône de la barre d&#39;état existe toujours, cliquez dessus pour réafficher la fenêtre.</span></span></code></pre></div><p>Le menu de la barre d&#39;état contient également deux actions courantes (très pratiques lorsque vous n&#39;utilisez pas l&#39;interface) :</p><ul><li>Changer de compte : passer au compte suivant</li><li>Rafraîchir le quota : rafraîchir le quota du compte actuel (notifiera également l&#39;interface pour rafraîchir l&#39;affichage)</li></ul><h3 id="etape-7-configurer-le-demarrage-automatique-au-demarrage-du-systeme-pour-qu-il-demarre-automatiquement-minimise" tabindex="-1">Étape 7 : Configurer le démarrage automatique au démarrage du système (pour qu&#39;il démarre automatiquement minimisé) <a class="header-anchor" href="#etape-7-configurer-le-demarrage-automatique-au-demarrage-du-systeme-pour-qu-il-demarre-automatiquement-minimise" aria-label="Permalink to &quot;Étape 7 : Configurer le démarrage automatique au démarrage du système (pour qu&#39;il démarre automatiquement minimisé)&quot;">​</a></h3><p><strong>Pourquoi</strong> Si vous souhaitez qu&#39;il fonctionne comme un &quot;service permanent&quot; (barre d&#39;état permanente + rafraîchissement en arrière-plan), le démarrage automatique au démarrage du système vous évitera d&#39;avoir à l&#39;ouvrir manuellement à chaque fois.</p><p>Dans Settings -&gt; General, trouvez &quot;Démarrage automatique au démarrage du système&quot;, choisissez Activer.</p><p><strong>Ce que vous devriez voir</strong> : Un message de succès s&#39;affiche après le basculement ; au prochain démarrage du système, il démarrera avec le paramètre <code>--minimized</code>.</p><div class="info custom-block"><p class="custom-block-title">Deux types de &quot;démarrage automatique&quot;, ne les confondez pas</p><table tabindex="0"><thead><tr><th>Nom</th><th>De quoi il s&#39;agit</th><th>Preuve</th></tr></thead><tbody><tr><td>Démarrage au démarrage du système</td><td>Antigravity Tools démarre automatiquement après le démarrage de l&#39;ordinateur (l&#39;application de bureau elle-même)</td><td>Les paramètres de démarrage contiennent <code>--minimized</code>, et la commande <code>toggle_auto_launch</code> est fournie</td></tr><tr><td>Démarrage automatique du proxy inverse</td><td>Après le démarrage d&#39;Antigravity Tools, si la configuration <code>proxy.auto_start=true</code>, il tente de démarrer automatiquement le service de proxy inverse local</td><td>L&#39;application lit la configuration au démarrage et exécute <code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><ul><li>[ ] Vous pouvez voir le chemin réel du répertoire de données dans Settings -&gt; Advanced</li><li>[ ] Vous pouvez ouvrir le répertoire de données et reconnaître globalement <code>accounts.json</code>, <code>accounts/</code>, <code>logs/</code>, <code>token_stats.db</code>, <code>proxy_logs.db</code></li><li>[ ] Vous savez que les journaux sont dans <code>logs/</code> et pouvez les consulter rapidement depuis la ligne de commande</li><li>[ ] Vous savez qu&#39;après avoir fermé la fenêtre, l&#39;application continue dans la barre d&#39;état ; pour quitter, utilisez Quit du menu de la barre d&#39;état</li><li>[ ] Vous pouvez distinguer &quot;démarrage au démarrage du système&quot; et &quot;démarrage automatique du proxy inverse&quot;</li></ul><h2 id="mises-en-garde-sur-les-pieges" tabindex="-1">Mises en garde sur les pièges <a class="header-anchor" href="#mises-en-garde-sur-les-pieges" aria-label="Permalink to &quot;Mises en garde sur les pièges&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scénario</th><th>Ce que vous pourriez faire (❌)</th><th>Approche recommandée (✓)</th></tr></thead><tbody><tr><td>Répertoire de données introuvable</td><td>Chercher au hasard le répertoire d&#39;installation de l&#39;App dans le système</td><td>Allez directement dans Settings -&gt; Advanced, regardez &quot;Répertoire de données&quot; et ouvrez en un clic</td></tr><tr><td>Fermer la fenêtre en pensant avoir quitté</td><td>Après avoir cliqué sur fermer la fenêtre, modifier la configuration/changer de port</td><td>Vérifiez d&#39;abord si l&#39;icône de la barre d&#39;état existe toujours ; pour quitter, utilisez Quit de la barre d&#39;état</td></tr><tr><td>Trop de journaux difficiles à dépanner</td><td>Chercher dans les anciens journaux tout en reproduisant le problème</td><td>D&#39;abord &quot;Vider les journaux&quot;, puis reproduire une fois, enfin regarder uniquement le fichier journal de cette fois</td></tr><tr><td>Modifier les données de compte</td><td>Modifier manuellement <code>accounts/*.json</code></td><td>Utilisez le flux d&#39;importation/exportation/migration de l&#39;interface (la section suivante liée expliquera)</td></tr></tbody></table><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><ul><li>Le répertoire de données est fixé dans <code>.antigravity_tools</code> sous Home (sur macOS/Linux, généralement un répertoire caché), comptes/journaux/bases de données statistiques sont tous ici</li><li>Le répertoire des journaux est <code>logs/</code>, priorité pour le dépannage ; si nécessaire, vous pouvez vider en un clic depuis la page des paramètres</li><li>Fermer la fenêtre cache dans la barre d&#39;état et continue de fonctionner ; pour quitter complètement, utilisez Quit de la barre d&#39;état</li><li>Le démarrage automatique a deux types : démarrage au démarrage du système (application) et démarrage automatique du proxy inverse (Proxy)</li></ul><hr><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Dans le prochain cours, nous apprendrons <strong><a href="./../add-account/">Ajouter un compte : double canal OAuth/Refresh Token et bonnes pratiques</a></strong>.</p></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer les emplacements du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Emplacement du répertoire de données (<code>~/.antigravity_tools</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>Index des comptes et répertoire des fichiers de comptes (<code>accounts.json</code> / <code>accounts/</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>Répertoire des journaux et rotation quotidienne (<code>logs/</code> + <code>app.log</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>Vider les journaux (tronquer les fichiers)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>Page des paramètres affiche le répertoire de données + ouverture en un clic</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>Page des paramètres vide les journaux en un clic (bouton + logique de fenêtre contextuelle)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>Page des paramètres vide les journaux en un clic (bouton onglet Advanced)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>Menu de la barre d&#39;état et événements de clic (changer de compte/rafraîchir/afficher/quitter)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Interrupteur de démarrage automatique (<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>Commandes d&#39;ouverture en un clic du répertoire de données / obtention du chemin / vidage des journaux</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Nom du fichier de base de données Token Stats (<code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Nom du fichier de base de données Proxy Monitor (<code>proxy_logs.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Nom du fichier d&#39;historique Warmup (<code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>Nom du fichier de paramètres de mise à jour (<code>update_settings.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>Démarrage automatique du proxy inverse (démarrage du service lorsque <code>proxy.auto_start=true</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details><h2 id="apercu-du-prochain-cours-1" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours-1" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Dans le prochain cours, nous apprendrons <strong><a href="./../add-account/">Ajouter un compte : double canal OAuth/Refresh Token et bonnes pratiques</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Quand utiliser OAuth et quand utiliser directement refresh_token</li><li>Comment gérer les échecs de rappel et l&#39;impossibilité d&#39;obtenir refresh_token</li><li>Comment importer refresh_token en masse pour créer rapidement un pool de comptes</li></ul></blockquote>`,69)])])}const h=t(o,[["render",i]]);export{m as __pageData,h as default};
